<template><view class="page"><view class="card"><text class="title">售后申请</text><picker :range="types" @change="typeIndex=Number($event.detail.value)"><view class="pick">{{types[typeIndex]}}</view></picker><input v-model="form.exchangeProduct" v-if="typeIndex===1" placeholder="换货商品"/><textarea v-model="form.description" placeholder="请描述售后原因"/><button class="primary" @click="submit">提交</button></view></view></template><script setup lang="ts">import { ref } from 'vue';import { onLoad } from '@dcloudio/uni-app';import { aftersaleApi } from '@/services/aftersale';const types=['退货','换货'];const typeIndex=ref(0);const form=ref<any>({orderId:'',type:'refund',description:'',exchangeProduct:''});onLoad((o:any)=>form.value.orderId=o.orderId||'');async function submit(){if(!form.value.description){uni.showToast({title:'请填写售后原因',icon:'none'});return}form.value.type=typeIndex.value===0?'refund':'exchange';await aftersaleApi.apply(form.value);uni.showToast({title:'已提交',icon:'success'});setTimeout(()=>uni.navigateBack(),400)}</script><style scoped lang="scss">.page{min-height:100vh;background:#f6f1e8;color:#24170c}.card{background:#fff;margin:20rpx;padding:28rpx;border-radius:16rpx}.title{display:block;font-size:34rpx;font-weight:900}.pick,input,textarea{background:#f8f4ed;border-radius:12rpx;padding:20rpx;margin-top:20rpx}textarea{width:auto;height:180rpx}button{margin-top:28rpx;height:84rpx;line-height:84rpx;width:100%;border:0;border-radius:999rpx}.primary{background:#b97700;color:#fff}button:after{border:0}</style>
